const t="https://wallhaven.cc/api/v1/search";const e={wallhaven:async function(){const e=new URLSearchParams({categories:"010",sorting:"random",purity:"100"}),o=await fetch(`${t}?${e}`);if(!o.ok)throw new Error(`Wallhaven failed: ${o.status}`);const r=await o.json();if(!r.data||0===r.data.length)throw new Error("No wallpapers found");const n=Math.floor(Math.random()*r.data.length),a=r.data[n];return{url:a.path,thumb:a.thumbs.large,source:"wallhaven",id:a.id,resolution:a.resolution}},picsum:async function(){const t=await fetch("https://picsum.photos/1920/1080/random",{redirect:"follow"});if(!t.ok)throw new Error(`Picsum failed: ${t.status}`);const e=t.url;return{url:e,thumb:e,source:"picsum",id:Date.now(),resolution:"1920x1080"}}};chrome.runtime.onMessage.addListener((t,o,r)=>{const n=t;if("FETCH_WALLPAPER"===n.type){const t=n.source||"wallhaven",o=e[t];return o?(o().then(t=>{r({wallpaper:t})}).catch(t=>{r({error:t.message})}),!0):(r({error:`Unknown source: ${t}`}),!0)}if("FETCH_SUGGESTIONS"===n.type)return fetch(`https://suggestqueries.google.com/complete/search?client=chrome&q=${encodeURIComponent(n.query||"")}`).then(t=>t.json()).then(t=>{r({suggestions:t[1]||[]})}).catch(()=>r({suggestions:[]})),!0});
